'use client';

import React, { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import { 
  Users, 
  MessageSquare, 
  History, 
  Wrench, 
  LogOut,
  ChevronDown,
  Loader2,
  User as UserIcon,
  Home
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { useUser, useAuth } from '@/firebase';
import { signOut } from 'firebase/auth';
import { Icons } from '@/components/icons';

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const pathname = usePathname();
  const auth = useAuth();
  const { user, isUserLoading } = useUser();
  const [isAuthorized, setIsAuthorized] = useState(false);

  useEffect(() => {
    if (isUserLoading) return;

    const isAdmin = localStorage.getItem('isAdmin');
    if (isAdmin !== 'true') {
      router.push('/login');
    } else if (!user) {
      router.push('/login');
    } else {
      setIsAuthorized(true);
    }
  }, [user, isUserLoading, router]);

  const handleLogout = async () => {
    localStorage.removeItem('isAdmin');
    await signOut(auth);
    router.push('/login');
  };

  if (isUserLoading || !isAuthorized) {
    return (
      <div className="flex h-screen items-center justify-center bg-[#F0F4F8]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const navLinks = [
    { href: '/admin/dashboard', label: 'Dashboard', icon: Home },
    { href: '/admin/users', label: 'Users', icon: Users },
    { href: '/admin/feedback', label: 'Feedback', icon: MessageSquare },
    { href: '/admin/email-history', label: 'Email History', icon: History },
    { href: '/admin/tools', label: 'Tools', icon: Wrench, hasSub: true },
  ];

  return (
    <div className="min-h-screen bg-[#F0F4F8] flex flex-col">
      {/* Top Green Stripe */}
      <div className="h-1.5 w-full bg-[#064e3b]" />

      {/* Space above navbar */}
      <div className="h-10 w-full" />

      {/* Admin Header */}
      <header className="bg-gradient-to-r from-primary to-accent text-white shadow-lg mx-4 rounded-xl overflow-hidden">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-10">
            <Link href="/admin/dashboard" className="flex items-center gap-2 group">
              <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center shadow-md">
                <Icons.Logo className="w-5 h-5" />
              </div>
              <span className="font-black text-lg tracking-tight whitespace-nowrap">Wallet Tally Admin</span>
            </Link>

            <nav className="hidden md:flex items-center gap-2">
              {navLinks.map((link) => (
                <Link
                  key={link.href}
                  href={link.href}
                  className={cn(
                    "flex items-center gap-2 px-4 py-2 rounded-lg transition-all text-xs font-bold uppercase tracking-wider",
                    pathname === link.href
                      ? "bg-white/20 shadow-inner backdrop-blur-sm" 
                      : "hover:bg-white/10"
                  )}
                >
                  <link.icon className="w-4 h-4" />
                  {link.label}
                  {link.hasSub && <ChevronDown className="w-3 h-3 ml-0.5 opacity-50" />}
                </Link>
              ))}
            </nav>
          </div>

          <div className="flex items-center gap-4">
            <Button 
              variant="ghost" 
              onClick={handleLogout}
              className="hidden lg:flex items-center gap-2 hover:bg-white/20 text-white font-bold text-xs uppercase tracking-widest border border-white/20 rounded-xl px-4"
            >
              <LogOut className="w-4 h-4" />
              Logout
            </Button>
            
            <div className="flex items-center gap-3 pl-4 border-l border-white/10">
              <div className="hidden lg:block text-right">
                <p className="text-[11px] font-black leading-none">Admin Session</p>
                <p className="text-[9px] text-white/60 leading-none mt-1 font-bold uppercase tracking-tighter">Secure Mode</p>
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" className="h-10 flex items-center gap-2 hover:bg-white/10 text-white rounded-xl px-2">
                    <UserIcon className="w-4 h-4" />
                    <ChevronDown className="w-3.5 h-3.5 opacity-50" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-48 rounded-2xl p-2 shadow-2xl border-0 mt-2">
                  <DropdownMenuItem onClick={handleLogout} className="text-red-500 font-bold focus:text-red-500 focus:bg-red-50 cursor-pointer rounded-xl h-11">
                    <LogOut className="w-4 h-4 mr-2" /> End Session
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 container mx-auto p-4 md:p-8 space-y-8">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col gap-1">
          <h1 className="text-4xl font-black text-[#1e293b] tracking-tight">
            {navLinks.find(l => l.href === pathname)?.label || 'Overview'}
          </h1>
          <p className="text-sm font-medium text-muted-foreground">Welcome back to the administrative control panel.</p>
        </div>
        <div className="space-y-8">
          {children}
        </div>
      </main>
    </div>
  );
}
